namespace sv_9ee9fef9a4c840bfa742c093a2a91cc0.Components;

public enum ScreenSize
{
    Mobile,
    Tablet,
    Desktop
}

export function initialize(dotNetRef) {
    function getCategory() {
        const width = window.innerWidth;
        if (width < 768) return "Mobile";
        if (width < 1024) return "Tablet";
        return "Desktop";
    }

    let current = getCategory();
    dotNetRef.invokeMethodAsync("OnBrowserResize", current);

    function onResize() {
        const updated = getCategory();
        if (updated !== current) {
            current = updated;
            dotNetRef.invokeMethodAsync("OnBrowserResize", current);
        }
    }

    window.addEventListener("resize", onResize);

    return {
        dispose: () => window.removeEventListener("resize", onResize)
    };
}

@implements IAsyncDisposable
@inject IJSRuntime JS

<CascadingValue Value="currentSize">
    @ChildContent
</CascadingValue>

@code {
    [Parameter]
    public RenderFragment? ChildContent { get; set; }

    private ScreenSize currentSize = ScreenSize.Desktop;
    private IJSObjectReference? module;
    private IJSObjectReference? listener;
    private DotNetObjectReference<ScreenSizeProvider>? dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            dotNetRef = DotNetObjectReference.Create(this);
            module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./js/screen-size.js");
            listener = await module.InvokeAsync<IJSObjectReference>(
                "initialize", dotNetRef);
        }
    }

    [JSInvokable]
    public void OnBrowserResize(string category)
    {
        if (Enum.TryParse<ScreenSize>(category, out var size) && size != currentSize)
        {
            currentSize = size;
            StateHasChanged();
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (listener is not null)
        {
            await listener.InvokeVoidAsync("dispose");
            await listener.DisposeAsync();
        }
        if (module is not null)
            await module.DisposeAsync();
        dotNetRef?.Dispose();
    }
}

